-- ==========================================
-- SEED: relaciona 115 condominios -> concessionarias
-- Gerado da planilha ATUALIZACAO DE COBRANCA 2025
-- Match por codigo prefixo (\d{3} no inicio do name)
-- Linhas que nao acharem condo correspondente sao DESCARTADAS (NULL)
-- ==========================================
-- Seed de condominios_concessionarias a partir da planilha "ATUALIZAÇÃO DE COBRANÇA 2025"
-- Match por codigo de prefixo (3 digitos no inicio do nome do condominio)
ON CONFLICT (condominio_id, concessionaria) DO NOTHING;

-- Limpa eventuais linhas com NULL (quando codigo nao bateu)
DELETE FROM public.condominios_concessionarias WHERE condominio_id IS NULL;
